import {
  reserveSeat,
  ReservationError,
  Database,
  Seat,
} from "./reserveSeat";

// ─── Test fixtures ────────────────────────────────────────────────────────────

const AVAILABLE_SEAT: Seat = { id: "A1", status: "available" };
const RESERVED_SEAT: Seat = { id: "A1", status: "reserved", userId: "user-99" };

function makeDb(overrides?: Partial<Database>): Database {
  return {
    findSeat: jest.fn().mockResolvedValue(AVAILABLE_SEAT),
    updateSeatStatus: jest.fn().mockResolvedValue(true),
    ...overrides,
  };
}

// ─── AC1: Happy path ──────────────────────────────────────────────────────────

describe("AC1 – available seat: returns a Reservation", () => {
  it("returns a Reservation with correct seatId and userId", async () => {
    const db = makeDb();
    const result = await reserveSeat("A1", "user-1", db);

    expect(result).toMatchObject({ seatId: "A1", userId: "user-1" });
    expect(result.reservedAt).toBeInstanceOf(Date);
  });

  it("calls findSeat then updateSeatStatus with correct arguments", async () => {
    const db = makeDb();
    await reserveSeat("A1", "user-1", db);

    expect(db.findSeat).toHaveBeenCalledWith("A1");
    expect(db.updateSeatStatus).toHaveBeenCalledWith("A1", "reserved", "user-1", "available");
  });
});

// ─── AC2: Seat already reserved ───────────────────────────────────────────────

describe("AC2 – already-reserved seat: throws SEAT_ALREADY_RESERVED", () => {
  it("throws ReservationError with code SEAT_ALREADY_RESERVED", async () => {
    const db = makeDb({
      findSeat: jest.fn().mockResolvedValue(RESERVED_SEAT),
    });

    await expect(reserveSeat("A1", "user-1", db)).rejects.toMatchObject({
      code: "SEAT_ALREADY_RESERVED",
    });
  });

  it("does NOT call updateSeatStatus when seat is already reserved", async () => {
    const db = makeDb({
      findSeat: jest.fn().mockResolvedValue(RESERVED_SEAT),
    });

    await expect(reserveSeat("A1", "user-1", db)).rejects.toThrow(ReservationError);

    expect(db.updateSeatStatus).not.toHaveBeenCalled();
  });
});

// ─── AC3: Concurrent calls — optimistic locking ───────────────────────────────

describe("AC3 – concurrent calls: exactly one succeeds, one throws SEAT_ALREADY_RESERVED", () => {
  it("resolves the race via optimistic locking: first writer wins, second throws", async () => {
    // Both calls read the seat as 'available' simultaneously.
    // updateSeatStatus simulates the DB atomic check: the first caller gets true,
    // the second gets false (the row was already updated).
    let updateCallCount = 0;
    const db = makeDb({
      findSeat: jest.fn().mockResolvedValue(AVAILABLE_SEAT),
      updateSeatStatus: jest.fn().mockImplementation(async () => {
        updateCallCount++;
        return updateCallCount === 1; // first caller succeeds, second fails
      }),
    });

    const [result1, result2] = await Promise.allSettled([
      reserveSeat("A1", "user-1", db),
      reserveSeat("A1", "user-2", db),
    ]);

    const successes = [result1, result2].filter((r) => r.status === "fulfilled");
    const failures = [result1, result2].filter((r) => r.status === "rejected");

    expect(successes).toHaveLength(1);
    expect(failures).toHaveLength(1);

    const failure = failures[0] as PromiseRejectedResult;
    expect(failure.reason).toBeInstanceOf(ReservationError);
    expect(failure.reason.code).toBe("SEAT_ALREADY_RESERVED");
  });

  it("never double-reserves: updateSeatStatus is called with expectedCurrentStatus='available'", async () => {
    // Ensures the optimistic-lock argument is always passed correctly
    const db = makeDb();
    await reserveSeat("A1", "user-1", db);

    expect(db.updateSeatStatus).toHaveBeenCalledWith(
      "A1",
      "reserved",
      "user-1",
      "available"   // the expectedCurrentStatus guard
    );
  });

  it("throws SEAT_ALREADY_RESERVED (not an unexpected error) when update returns false", async () => {
    const db = makeDb({
      updateSeatStatus: jest.fn().mockResolvedValue(false),
    });

    const err = await reserveSeat("A1", "user-1", db).catch((e) => e);

    expect(err).toBeInstanceOf(ReservationError);
    expect(err.code).toBe("SEAT_ALREADY_RESERVED");
  });
});

// ─── AC4: Seat does not exist ─────────────────────────────────────────────────

describe("AC4 – seat not found: throws SEAT_NOT_FOUND", () => {
  it("throws ReservationError with code SEAT_NOT_FOUND when findSeat returns null", async () => {
    const db = makeDb({
      findSeat: jest.fn().mockResolvedValue(null),
    });

    await expect(reserveSeat("Z99", "user-1", db)).rejects.toMatchObject({
      code: "SEAT_NOT_FOUND",
    });
  });

  it("does NOT call updateSeatStatus when seat is not found", async () => {
    const db = makeDb({
      findSeat: jest.fn().mockResolvedValue(null),
    });

    await expect(reserveSeat("Z99", "user-1", db)).rejects.toThrow(ReservationError);

    expect(db.updateSeatStatus).not.toHaveBeenCalled();
  });
});

// ─── ReservationError class ───────────────────────────────────────────────────

describe("ReservationError class", () => {
  it("has name='ReservationError', code, and inherits from Error", () => {
    const err = new ReservationError("SEAT_NOT_FOUND", "not found");

    expect(err.name).toBe("ReservationError");
    expect(err.code).toBe("SEAT_NOT_FOUND");
    expect(err.message).toBe("not found");
    expect(err).toBeInstanceOf(Error);
  });
});

